import { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";
import { Building2, Upload, Save, Image as ImageIcon } from "lucide-react";

/**
 * =========================
 * SMART-M HUB 3-LAYER SYSTEM
 * =========================
 */

const SchoolProfilePage = ({ mode = "auto" }) => {
  const user = authService.getUser();

  const [school, setSchool] = useState(null);
  const [loading, setLoading] = useState(true);
  const [step, setStep] = useState("landing"); 
  // landing | register | profile

  const [logoPreview, setLogoPreview] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    address: "",
    phone: "",
    email: "",
    school_type: "",
    logo_url: "",
    admin_name: "",
    admin_email: "",
    admin_password: ""
  });

  /**
   * =========================
   * LOAD SCHOOL (IF EXISTS)
   * =========================
   */
  useEffect(() => {
    const init = async () => {
      try {
        if (user?.school_id) {
          const res = await apiClient.get(`/schools/${user.school_id}`);
          setSchool(res.data);
          setStep("profile");
        } else {
          setStep("landing");
        }
      } catch (err) {
        setStep("landing");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, []);

  /**
   * =========================
   * LAYER 2: REGISTER SCHOOL
   * =========================
   */
  const handleRegisterSchool = async (e) => {
    e.preventDefault();
    try {
      const res = await apiClient.post("/auth/register-school", formData);

      toast.success("School registered successfully");

      // store login context update if backend returns user
      if (res.data?.user_id) {
        setStep("profile");
        window.location.reload();
      }
    } catch (err) {
      toast.error(err.response?.data?.detail || "Registration failed");
    }
  };

  /**
   * =========================
   * LAYER 3: UPDATE PROFILE
   * =========================
   */
  const handleUpdateProfile = async (e) => {
    e.preventDefault();
    try {
      await apiClient.patch(`/schools/${user.school_id}`, formData);
      toast.success("School updated successfully");
    } catch (err) {
      toast.error("Failed to update school");
    }
  };

  /**
   * =========================
   * LOGO HANDLER
   * =========================
   */
  const handleLogoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      setLogoPreview(reader.result);
      setFormData({ ...formData, logo_url: reader.result });
    };
    reader.readAsDataURL(file);
  };

  if (loading) {
    return <div className="p-10 text-slate-400">Loading Smart-M Hub...</div>;
  }

  /**
   * =========================
   * 🔵 LAYER 1: PUBLIC LANDING
   * =========================
   */
  if (step === "landing") {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#0B1120] p-6">
        <div className="max-w-2xl text-center space-y-6">

          <div className="flex justify-center">
            <div className="w-20 h-20 bg-emerald-600 rounded-2xl flex items-center justify-center">
              <Building2 className="text-white w-10 h-10" />
            </div>
          </div>

          <h1 className="text-4xl font-bold text-white">Smart-M Hub</h1>

          <p className="text-slate-400">
            A unified school management system for learning, finance, and administration.
            Built to simplify education operations across Africa.
          </p>

          <div className="text-slate-400 text-sm">
            Contact: support@smartmhub.com
          </div>

          <Button
            onClick={() => setStep("register")}
            className="bg-emerald-600 hover:bg-emerald-500"
          >
            Register a School
          </Button>
        </div>
      </div>
    );
  }

  /**
   * =========================
   * 🟡 LAYER 2: SCHOOL REGISTRATION
   * =========================
   */
  if (step === "register") {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-[#0B1120]">
        <form onSubmit={handleRegisterSchool} className="w-full max-w-xl space-y-4 bg-[#1A2332] p-6 rounded-xl">

          <h2 className="text-white text-xl font-bold">Register School</h2>

          <div>
            <Label>School Logo</Label>
            <Input type="file" onChange={handleLogoUpload} />
          </div>

          <Input placeholder="School Name" onChange={(e) => setFormData({ ...formData, name: e.target.value })} />
          <Input placeholder="Address" onChange={(e) => setFormData({ ...formData, address: e.target.value })} />
          <Input placeholder="Phone" onChange={(e) => setFormData({ ...formData, phone: e.target.value })} />
          <Input placeholder="School Email" onChange={(e) => setFormData({ ...formData, email: e.target.value })} />

          <Input placeholder="Admin Name" onChange={(e) => setFormData({ ...formData, admin_name: e.target.value })} />
          <Input placeholder="Admin Email" onChange={(e) => setFormData({ ...formData, admin_email: e.target.value })} />
          <Input type="password" placeholder="Admin Password" onChange={(e) => setFormData({ ...formData, admin_password: e.target.value })} />

          <Select onValueChange={(v) => setFormData({ ...formData, school_type: v })}>
            <SelectTrigger>
              <SelectValue placeholder="School Type" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="primary">Primary</SelectItem>
              <SelectItem value="secondary">Secondary</SelectItem>
              <SelectItem value="college">College</SelectItem>
            </SelectContent>
          </Select>

          <Button type="submit" className="w-full bg-emerald-600">
            Create School
          </Button>
        </form>
      </div>
    );
  }

  /**
   * =========================
   * 🔴 LAYER 3: SCHOOL PROFILE (AFTER CREATION)
   * =========================
   */
  return (
    <div className="p-6 space-y-6">

      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-white">School Profile</h2>
      </div>

      <form onSubmit={handleUpdateProfile} className="space-y-4">

        <Input
          value={formData.name}
          onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          placeholder="School Name"
        />

        <Textarea
          value={formData.address}
          onChange={(e) => setFormData({ ...formData, address: e.target.value })}
          placeholder="Address"
        />

        <Input
          value={formData.phone}
          onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
          placeholder="Phone"
        />

        <Input
          value={formData.email}
          onChange={(e) => setFormData({ ...formData, email: e.target.value })}
          placeholder="Email"
        />

        <Button type="submit" className="bg-emerald-600">
          Save Changes
        </Button>

      </form>

    </div>
  );
};

export default SchoolProfilePage;
